using Forge.Core.Entities;
using Forge.Core.Enums;
using Forge.Data.Context;

using Serilog;

namespace Forge.Api.Data.TrainingContent;

public class PayablesTraining : TrainingContentBase
{
    public PayablesTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Payables Overview",
            Slug = "payables-overview",
            Summary = "What Accounts Payable covers: vendor bills, vendor payments, the bill lifecycle, payment application, and how payables connect to Purchase Orders and Vendors.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/payables"]""",
            Tags = """["payables","ap","accounting"]""",
            ContentJson = """{"body":"## Payables Overview\n\nThe Payables module is your Accounts Payable (AP) workspace. It tracks the money your shop owes vendors: the **vendor bills** you receive, the **vendor payments** you make to settle them, and the way those payments are applied against open balances. Payables connects directly to Purchase Orders (for matched billing) and to Vendors (every bill and payment belongs to one vendor).\n\nThe page is organized into tabs — **Bills**, **Payments**, **Batches**, and **Accounts** — with a vendor filter and a status filter at the top to narrow what you see.\n\n### What Is a Vendor Bill?\n\nA vendor bill represents an invoice you owe a vendor. Each bill has:\n- A unique **Bill Number** (auto-generated)\n- A link to exactly one **Vendor**\n- An optional **Vendor Invoice #** (the vendor's own reference)\n- A **Bill Date** and a **Due Date**\n- One or more **Line Items** (description, quantity, unit price)\n- An optional **Tax Amount**\n- A **Status** that drives where the bill is in its lifecycle\n- Computed totals: **Total**, **Paid** (amount paid), and **Balance Due**\n\nBills can be entered two ways. A **standalone** bill is typed in by hand — you add free-form line items. A **From Purchase Order** bill is matched to a PO: you pick the PO and bill against its received lines, and you can only bill up to the quantity that has been received but not yet billed (three-way matching).\n\n### Bill Lifecycle\n\nVendor bills move through these statuses:\n\n1. **Draft** — The bill has been entered but not yet approved. It has no general-ledger impact yet. This is the initial status for every new bill.\n2. **Approved** — The bill has been approved for payment. The AP journal posts on this transition. Approve a bill from the detail panel using the **Approve Bill** button (available only from Draft).\n3. **Partially Paid** — The bill is approved and one or more vendor payments have settled part of the balance. Balance Due is still greater than zero.\n4. **Paid** — The bill is fully settled. Balance Due is zero.\n5. **Void** — The bill was cancelled before it was paid. A bill can be voided only from Draft or Approved status, only when nothing has been paid against it, and only when it did not originate from an expense.\n\n### What Is a Vendor Payment?\n\nA vendor payment records money sent to a vendor and how it is applied to that vendor's open bills. Each payment has:\n- A unique **Payment #** (auto-generated)\n- A **Vendor**\n- A **Method** (Cash, Check, Credit Card, Bank Transfer, Wire, or Other)\n- An **Amount**\n- A **Payment Date**\n- An optional **Reference #** (check number, wire reference, etc.)\n- One or more **Bill Applications** that spread the payment across open bills\n\nWhen you create a payment, you choose a vendor and the system loads that vendor's payable bills (those in Approved or Partially Paid status). You enter how much of the payment to apply to each bill. The sum of applications may not exceed the payment amount; anything left over shows as **Unapplied**. Applying a payment moves each affected bill toward Partially Paid or Paid automatically.\n\n### Payment Transmission (Electronic Payments)\n\nElectronic payments — Bank Transfer and Wire — carry a **Transmission Status** that tracks the bank handoff: Queued, Retrying, Succeeded, Failed, or Cancelled. A failed transmission surfaces a banner at the top of the page and on the bill and payment detail. You can **Retry Transmission** on a failed payment. Wire payments add a dual-control step: while a wire is Queued you must **Attest Wire** (a second user confirms it) before it transmits.\n\n### How Payables Connects to Other Features\n\n**Purchase Orders:** A bill created From Purchase Order is matched line-by-line to the PO's received quantities. You can only bill received-but-unbilled quantity, and price differences flow through as purchase-price variance when the bill posts.\n\n**Vendors:** Every bill and payment belongs to one vendor. The vendor name links to the vendor record, and the vendor filter at the top of the page scopes both the Bills and Payments tabs.\n\n**Expenses:** A vendor-settled expense can be promoted into a vendor bill automatically. Such a bill shows a 'From Expense' chip and cannot be voided.\n\n**Accounting boundary:** Payables is an accounting feature. When an external accounting provider is connected, AP is managed there instead; the built-in AP module runs in standalone mode.\n\n### When to Use Payables\n\n- When a vendor invoice arrives — enter it as a bill, then approve it for payment\n- When you want three-way matching — create the bill From Purchase Order so billing is bounded by received quantity\n- When you pay a vendor — record a payment and apply it across that vendor's open bills\n- When an electronic payment fails — retry the transmission from the payment detail\n- When you need a wire approved — attest the queued wire before it sends","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Payables — Guided Tour",
            Slug = "payables-walkthrough",
            Summary = "A guided tour of the Payables page: the Bills and Payments tabs, vendor and status filters, the data tables, creating bills, recording payments, and the detail panels.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/payables"]""",
            Tags = """["payables","ap","accounting","walkthrough"]""",
            ContentJson = """{"appRoute":"/payables","startButtonLabel":"Tour Payables","steps":[{"element":".tab-bar","popover":{"title":"Payables Tabs","description":"The Payables page is split into tabs: Bills (vendor invoices you owe), Payments (money sent to vendors), Batches (payment batches), and Accounts (vendor bank accounts). The Bills and Payments tabs are the day-to-day AP workspace.","side":"bottom"}},{"element":"[data-testid='new-vendor-bill-btn']","popover":{"title":"New Bill Button","description":"On the Bills tab, click here to enter a vendor bill. You pick a vendor, set the bill and due dates, and add line items — either as free-form standalone lines or matched From Purchase Order. New bills start in Draft status with no general-ledger impact.","side":"bottom"}},{"element":".filters-bar app-select","popover":{"title":"Vendor and Status Filters","description":"Filter the table by vendor (All Vendors by default) and by status. The Bills status filter offers Draft, Approved, Partially Paid, Paid, and Void. The Payments tab filters by payment method and transmission status instead.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Bills Table","description":"Each row is a vendor bill: Bill Number, Vendor, Vendor Invoice #, a color-coded Status chip, Bill Date, Due Date, Total, Paid, and Balance Due. Balance Due is highlighted when it is greater than zero. Click any row to open the bill detail panel.","side":"top"}},{"element":"[data-testid='new-vendor-payment-btn']","popover":{"title":"New Payment Button","description":"On the Payments tab, click here to record a vendor payment. After choosing the vendor, the dialog loads that vendor's payable bills (Approved or Partially Paid) so you can apply the payment across them. The dialog uses data-testids like vendor-payment-method, vendor-payment-amount, and vendor-payment-app-amount.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Bill Detail Panel","description":"Clicking a bill row opens its detail panel: status chip, vendor link, linked Purchase Order, line items, and the totals block (Subtotal, Tax, Total, Paid, Balance Due). Action buttons appear by status — Approve Bill (data-testid approve-bill-btn) from Draft, and Void Bill (data-testid void-bill-btn) from Draft or Approved when nothing has been paid.","side":"top"}},{"element":"app-data-table","popover":{"title":"Payment Detail Panel","description":"On the Payments tab, clicking a payment row opens its detail: vendor, method, amount, applied and unapplied amounts, and the bill applications table. For electronic payments a Bank Transmission section shows status and attempts, with Retry Transmission for failures, Attest Wire for queued wires, and Void Payment to reverse a payment.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Payables Field Reference",
            Slug = "payables-field-reference",
            Summary = "Complete reference for every field, button, status, validation rule, and table column in the Payables module — vendor bills and vendor payments.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/payables"]""",
            Tags = """["payables","ap","accounting","reference"]""",
            ContentJson = """{"title":"Payables Field Reference","groups":[{"heading":"Vendor Bill Form Fields (Create Dialog)","items":[{"label":"Vendor (required)","value":"Select dropdown, active vendors only. The vendor this bill is owed to. data-testid: bill-vendor"},{"label":"Vendor Invoice # (optional)","value":"Text input. The vendor's own invoice reference. Placeholder 'Optional'. Shown in the table; '—' when blank. data-testid: bill-vendor-invoice-number"},{"label":"Bill Date (required)","value":"Datepicker. The date on the vendor's invoice. Maximum is today. data-testid: bill-date"},{"label":"Due Date (required)","value":"Datepicker. The date payment is due. data-testid: bill-due-date"},{"label":"Tax Amount (optional)","value":"Currency input. Tax on the bill, added on top of the line subtotal. Minimum 0, defaults to 0. data-testid: bill-tax-amount"},{"label":"Currency (multi-currency installs)","value":"Select. The bill currency. Shown only when more than one active currency exists; defaults to the base currency. data-testid: bill-currency"},{"label":"FX Rate (non-base currency)","value":"Number input. Exchange rate to the base currency. Shown only when a non-base currency is selected. data-testid: bill-fx-rate"},{"label":"From Purchase Order (toggle)","value":"Switches the dialog between standalone entry and PO-matched billing. data-testid: bill-from-po-toggle"},{"label":"Purchase Order (PO mode)","value":"Select. The PO to bill against; required when From Purchase Order is on. data-testid: bill-po-select"},{"label":"Notes (optional)","value":"Textarea, 2 rows. Free-form notes about the bill. data-testid: bill-notes"}]},{"heading":"Bill Line Item Fields","items":[{"label":"Part (standalone, optional)","value":"Entity picker showing part number and name. Optional link from a line to a part."},{"label":"Description (standalone, required)","value":"Text input. Required on each standalone line. data-testid: bill-line-desc"},{"label":"Quantity (standalone, required)","value":"Number input, minimum 0.0001. data-testid: bill-line-qty"},{"label":"Unit Price (standalone, required)","value":"Number input, minimum 0. data-testid: bill-line-price"},{"label":"Add Line (standalone)","value":"Adds a standalone line item. data-testid: bill-add-line-btn"},{"label":"Quantity to Bill (PO mode, required)","value":"Number input. Cannot exceed the received-but-unbilled quantity on the PO line (three-way match). data-testid: bill-po-line-qty"},{"label":"Unit Price (PO mode, required)","value":"Number input, pre-filled from the PO line price. Differences post as purchase-price variance. data-testid: bill-po-line-price"}]},{"heading":"Vendor Bill Statuses","items":[{"label":"Draft (blue chip)","value":"Entered but not approved. No general-ledger impact. Initial status. Can be approved or voided."},{"label":"Approved (teal/primary chip)","value":"Approved for payment; the AP journal posts on this transition. Eligible for payment application. Can still be voided if nothing is paid."},{"label":"Partially Paid (amber/warning chip)","value":"Approved and partially settled by one or more payments. Balance Due is greater than zero."},{"label":"Paid (green/success chip)","value":"Fully settled. Balance Due is zero. Terminal status."},{"label":"Void (gray/muted chip)","value":"Cancelled before payment. Terminal status. Posted bills are reversed rather than voided."},{"label":"From Expense (info chip)","value":"Shown when the bill was auto-promoted from a vendor-settled expense (sourceExpenseId). Such bills cannot be voided."},{"label":"Payment Failed (error chip)","value":"Shown on a bill row when a related electronic payment had a failed transmission."}]},{"heading":"Vendor Payment Form Fields (Create Dialog)","items":[{"label":"Vendor (required)","value":"Select dropdown, active vendors only. Choosing a vendor loads that vendor's payable bills. data-testid: vendor-payment-vendor"},{"label":"Method (required)","value":"Select: Cash, Check, Credit Card, Bank Transfer, Wire, or Other. data-testid: vendor-payment-method"},{"label":"Amount (required)","value":"Currency input, minimum 0.01. The total payment amount. data-testid: vendor-payment-amount"},{"label":"Payment Date (required)","value":"Datepicker, maximum today. data-testid: vendor-payment-date"},{"label":"Reference # (optional)","value":"Text input. Check number, wire reference, etc. data-testid: vendor-payment-ref"},{"label":"Amount to Apply (per bill)","value":"Number input per application row. Bounded by that bill's Balance Due. data-testid: vendor-payment-app-amount"},{"label":"Settlement FX Rate (per bill, multi-currency)","value":"Number input per application row when multi-currency is active. data-testid: vendor-payment-app-fx"},{"label":"Notes (optional)","value":"Textarea, 2 rows. data-testid: vendor-payment-notes"}]},{"heading":"Payment Methods","items":[{"label":"Cash","value":"Cash payment."},{"label":"Check","value":"Paper check; the check number typically goes in Reference #."},{"label":"Credit Card","value":"Credit card payment."},{"label":"Bank Transfer","value":"Electronic ACH-style transfer; carries a transmission status."},{"label":"Wire","value":"Wire transfer; carries a transmission status and requires dual-control wire attestation while queued."},{"label":"Other","value":"Any method not covered above."}]},{"heading":"Payment Transmission Statuses (Electronic Payments)","items":[{"label":"Queued (info chip)","value":"Transmission is waiting to be sent. Wire payments must be attested while in this status."},{"label":"Retrying (warning chip)","value":"A send attempt failed and a retry is scheduled; shows the attempt count and next attempt time."},{"label":"Succeeded (success chip)","value":"Transmission completed; a submission reference is recorded."},{"label":"Failed (error chip)","value":"All attempts failed. Surfaces a banner and enables Retry Transmission."},{"label":"Cancelled (muted chip)","value":"Transmission was cancelled."}]},{"heading":"Bill Detail Buttons and Actions","items":[{"label":"Approve Bill","value":"Transitions a Draft bill to Approved and posts the AP journal. Available only from Draft. Confirms before proceeding. data-testid: approve-bill-btn"},{"label":"Void Bill","value":"Cancels a bill with no GL impact. Available only from Draft or Approved, only when amount paid is 0 and the bill did not come from an expense. Confirms before proceeding. data-testid: void-bill-btn"},{"label":"Save / Create Bill","value":"Creates the bill. Disabled when the form is invalid, there are no line items, or a save is in progress. data-testid: bill-save-btn"}]},{"heading":"Payment Detail Buttons and Actions","items":[{"label":"Retry Transmission","value":"Re-attempts a failed electronic payment transmission. Available when transmission status is Failed. data-testid: retry-transmission-btn"},{"label":"Attest Wire","value":"Second-user confirmation that releases a wire for transmission. Available when method is Wire and transmission status is Queued. data-testid: attest-wire-btn"},{"label":"Void Payment","value":"Reverses a payment; opens a dialog requiring a void reason. data-testid: void-payment-btn (reason: void-reason, confirm: void-confirm-btn)"},{"label":"Save / Create Payment","value":"Creates the payment and its bill applications. Disabled when the form is invalid, the payment is over-applied, or a save is in progress. data-testid: vendor-payment-save-btn"}]},{"heading":"Validation Rules","items":[{"label":"Bill — Vendor","value":"Required. Must select an active vendor."},{"label":"Bill — Bill Date","value":"Required. Must be today or earlier."},{"label":"Bill — Due Date","value":"Required."},{"label":"Bill — Line Items","value":"At least one active line is required. Standalone lines require a description, quantity >= 0.0001, and unit price >= 0."},{"label":"Bill — From Purchase Order","value":"When on, a Purchase Order is required and each line's Quantity to Bill cannot exceed the received-but-unbilled quantity."},{"label":"Bill — Save disabled when","value":"The form is invalid, no active lines exist, or a save is in progress."},{"label":"Payment — Vendor, Method, Amount, Date","value":"All required. Amount must be at least 0.01. Payment Date must be today or earlier."},{"label":"Payment — Applications","value":"Each application is bounded by the bill's Balance Due. The total applied may not exceed the payment amount (otherwise the payment is over-applied)."},{"label":"Payment — Save disabled when","value":"The form is invalid, the payment is over-applied, or a save is in progress."}]},{"heading":"Bills Table Columns","items":[{"label":"Bill Number","value":"Sortable. Auto-generated bill number in monospace font."},{"label":"Vendor","value":"Sortable. Vendor name."},{"label":"Vendor Invoice #","value":"Sortable. The vendor's reference, monospace; '—' when blank."},{"label":"Status","value":"Sortable, filterable. Color-coded chip: Draft (blue), Approved (teal), Partially Paid (amber), Paid (green), Void (gray)."},{"label":"Bill Date","value":"Sortable. Date, formatted MM/dd/yyyy."},{"label":"Due Date","value":"Sortable. Date, formatted MM/dd/yyyy."},{"label":"Total","value":"Sortable. Currency, right-aligned."},{"label":"Paid","value":"Sortable. Amount paid, currency, right-aligned."},{"label":"Balance Due","value":"Sortable. Currency, right-aligned; highlighted when greater than zero."}]},{"heading":"Payments Table Columns","items":[{"label":"Payment #","value":"Sortable. Auto-generated payment number in monospace font."},{"label":"Vendor","value":"Sortable. Vendor name."},{"label":"Method","value":"Sortable, filterable. Payment method (Cash, Check, Credit Card, Bank Transfer, Wire, Other)."},{"label":"Amount","value":"Sortable. Currency, right-aligned."},{"label":"Applied","value":"Sortable. Amount applied to bills, currency, right-aligned."},{"label":"Unapplied","value":"Sortable. Amount not yet applied, currency; highlighted when greater than zero."},{"label":"Payment Date","value":"Sortable. Date, formatted MM/dd/yyyy."},{"label":"Reference #","value":"Sortable. Check or wire reference."},{"label":"Transmission Status","value":"Sortable, filterable. Color-coded chip for electronic payments: Queued (blue), Retrying (amber), Succeeded (green), Failed (red), Cancelled (gray); '—' when not applicable."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Payables Knowledge Check",
            Slug = "payables-quiz",
            Summary = "Test your knowledge of the Payables module: vendor bills, the bill lifecycle, payment application, PO-matched billing, transmission, and validation.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/payables"]""",
            Tags = """["payables","ap","accounting","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"pa1","text":"A vendor invoice just arrived. What is the first step to record it in Payables?","options":[{"id":"a","text":"Go to Purchase Orders and mark the PO as billed"},{"id":"b","text":"On the Bills tab, click New Bill, select the vendor, set the bill and due dates, add line items, and save","isCorrect":true},{"id":"c","text":"Record a payment first and the bill is created automatically"},{"id":"d","text":"Create the bill from the Vendors page under a Billing tab"}],"explanation":"Vendor bills are entered from the Bills tab. Click New Bill, pick the vendor, set the Bill Date and Due Date, add line items (standalone or From Purchase Order), and save. New bills start in Draft status."},{"id":"pa2","text":"What is the correct lifecycle of a vendor bill?","options":[{"id":"a","text":"Open → Processing → Closed"},{"id":"b","text":"Draft → Approved → Partially Paid → Paid (or Void from Draft/Approved)","isCorrect":true},{"id":"c","text":"Pending → Sent → Received → Settled"},{"id":"d","text":"Entered → Posted → Reconciled"}],"explanation":"A bill starts in Draft (no GL impact), moves to Approved when you approve it (the AP journal posts), then to Partially Paid and Paid as payments are applied. A bill can be voided only from Draft or Approved."},{"id":"pa3","text":"When does a vendor bill post to the general ledger?","options":[{"id":"a","text":"As soon as it is saved in Draft"},{"id":"b","text":"When it is approved (the Draft → Approved transition posts the AP journal)","isCorrect":true},{"id":"c","text":"Only when it is fully paid"},{"id":"d","text":"Bills never post to the general ledger"}],"explanation":"A Draft bill has no general-ledger impact. The AP journal posts on the transition to Approved, which you trigger with the Approve Bill button (available only from Draft)."},{"id":"pa4","text":"You want to bill against a Purchase Order. What constrains how much you can bill on each line?","options":[{"id":"a","text":"The ordered quantity on the PO"},{"id":"b","text":"The received-but-unbilled quantity (three-way matching)","isCorrect":true},{"id":"c","text":"There is no limit; you can bill any quantity"},{"id":"d","text":"The vendor's credit limit"}],"explanation":"With the From Purchase Order toggle on, each line's Quantity to Bill cannot exceed the quantity received but not yet billed. This is three-way matching; price differences from the PO post as purchase-price variance."},{"id":"pa5","text":"How does a vendor payment get applied to bills?","options":[{"id":"a","text":"It automatically pays the oldest bill in full with no choices"},{"id":"b","text":"After selecting the vendor, the dialog loads payable bills (Approved or Partially Paid) and you enter how much to apply to each","isCorrect":true},{"id":"c","text":"Payments cannot be applied to bills; they are separate records"},{"id":"d","text":"You must approve each application from the bill detail later"}],"explanation":"When you pick a vendor on a new payment, the dialog loads that vendor's payable bills (Approved or Partially Paid). You enter an amount to apply per bill, each bounded by that bill's Balance Due. Applying the payment moves bills to Partially Paid or Paid."},{"id":"pa6","text":"On a new payment, what does the Unapplied amount represent?","options":[{"id":"a","text":"The tax portion of the payment"},{"id":"b","text":"The part of the payment amount not yet applied to any bill","isCorrect":true},{"id":"c","text":"The amount the vendor still owes you"},{"id":"d","text":"A required deposit that must equal zero"}],"explanation":"Unapplied is the payment amount minus the total applied across bills. It is highlighted when greater than zero. The total applied may not exceed the payment amount, or the payment is over-applied and Save is disabled."},{"id":"pa7","text":"Which conditions must all be true to void a vendor bill?","options":[{"id":"a","text":"The bill must be Paid"},{"id":"b","text":"The bill is Draft or Approved, nothing has been paid against it, and it did not come from an expense","isCorrect":true},{"id":"c","text":"Any bill can be voided at any time"},{"id":"d","text":"Only bills with a linked Purchase Order can be voided"}],"explanation":"Void Bill is available only from Draft or Approved status, only when the amount paid is zero, and only when the bill did not originate from a promoted expense. Posted/paid bills are reversed rather than voided."},{"id":"pa8","text":"An electronic payment shows a Failed transmission status. What can you do?","options":[{"id":"a","text":"Nothing; you must delete it and start over"},{"id":"b","text":"Open the payment detail and click Retry Transmission","isCorrect":true},{"id":"c","text":"Change its method to Cash to clear the error"},{"id":"d","text":"Wait; failed transmissions retry indefinitely on their own"}],"explanation":"A failed transmission surfaces a banner and enables the Retry Transmission button on the payment detail. Bank Transfer and Wire payments carry a transmission status (Queued, Retrying, Succeeded, Failed, Cancelled)."},{"id":"pa9","text":"What extra step does a Wire payment require before it transmits?","options":[{"id":"a","text":"Nothing different from a Bank Transfer"},{"id":"b","text":"While the wire is Queued, a second user must Attest Wire (dual control)","isCorrect":true},{"id":"c","text":"The vendor must confirm receipt first"},{"id":"d","text":"It must be split into multiple smaller payments"}],"explanation":"Wire payments add a dual-control step: while the transmission is Queued, the Attest Wire button lets a second user confirm and release the wire before it sends."},{"id":"pa10","text":"What is required to save a new vendor bill?","options":[{"id":"a","text":"Only a vendor selection"},{"id":"b","text":"A vendor, a Bill Date (today or earlier), a Due Date, and at least one valid line item","isCorrect":true},{"id":"c","text":"A vendor, a tax amount, and notes"},{"id":"d","text":"A linked Purchase Order in every case"}],"explanation":"Save is disabled until the form is valid and at least one active line exists. Required fields are Vendor, Bill Date (max today), and Due Date; standalone lines need a description, quantity, and unit price. A PO is required only when From Purchase Order is on."},{"id":"pa11","text":"A bill row shows a 'From Expense' chip. What does that tell you?","options":[{"id":"a","text":"The bill is overdue"},{"id":"b","text":"The bill was auto-promoted from a vendor-settled expense and cannot be voided","isCorrect":true},{"id":"c","text":"The bill has no line items"},{"id":"d","text":"The bill was imported from an external accounting system"}],"explanation":"A 'From Expense' chip means the bill was created by promoting a vendor-settled expense (it carries a sourceExpenseId). One consequence is that such bills cannot be voided."},{"id":"pa12","text":"How do the vendor and status filters at the top of the page behave?","options":[{"id":"a","text":"They only affect the Batches tab"},{"id":"b","text":"The vendor filter scopes the visible rows, and the status filter offers status options appropriate to the active tab (bill statuses on Bills, method/transmission on Payments)","isCorrect":true},{"id":"c","text":"They permanently delete rows that do not match"},{"id":"d","text":"They are read-only and only display the current vendor"}],"explanation":"The vendor filter narrows rows to one vendor (All Vendors by default). The status filter adapts to the tab: the Bills tab filters by bill status (Draft, Approved, Partially Paid, Paid, Void), while the Payments tab filters by method and transmission status."}]}"""
        });

        Log.Information("Seeded Payables training modules");
    }
}
